import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Header from '../components/Header';
import MovieCard from '../components/MovieCard';
import MoviePlayer from '../components/MoviePlayer';
import { useAuth } from '../contexts/AuthContext';
import { MOVIES } from '../services/api';
import './Saved.css';

const Saved = () => {
  const { user } = useAuth();
  const [savedMovies, setSavedMovies] = useState([]);
  const [selectedMovie, setSelectedMovie] = useState(null);

  useEffect(() => {
    if (user) {
      const saved = localStorage.getItem(`saved_${user.email}`);
      const savedIds = saved ? JSON.parse(saved) : [];
      const movies = savedIds.map(id => MOVIES[id]).filter(m => m);
      setSavedMovies(movies);
    }
  }, [user]);

  const handleMovieClick = (movie) => {
    setSelectedMovie(movie);
  };

  const handleClosePlayer = () => {
    setSelectedMovie(null);
  };

  if (!user) {
    return (
      <>
        <Header />
        <main className="saved-container">
          <div className="login-prompt">
            <h2>🔒 Требуется регистрация</h2>
            <p>Чтобы сохранять фильмы и видеть свои отложенные, нужно войти в аккаунт</p>
            <Link to="/register" className="login-prompt-btn">Зарегистрироваться</Link>
          </div>
        </main>
      </>
    );
  }

  return (
    <>
      <Header />
      <main className="saved-container">
        <div className="saved-header">
          <h1 className="saved-title">📌 ОТЛОЖЕННЫЕ</h1>
          {savedMovies.length > 0 && (
            <span className="saved-count">{savedMovies.length} фильмов</span>
          )}
        </div>

        {savedMovies.length === 0 ? (
          <div className="empty-saved">
            <div className="icon">📭</div>
            <p>У вас пока нет отложенных фильмов</p>
            <p style={{ fontSize: '1rem', marginTop: '1rem' }}>
              Листайте клипы и сохраняйте интересные фильмы
            </p>
            <Link to="/clips" className="empty-link">
              Перейти к клипам →
            </Link>
          </div>
        ) : (
          <div className="movies-grid">
            {savedMovies.map(movie => (
              <MovieCard
                key={movie.id}
                movie={movie}
                onClick={() => handleMovieClick(movie)}
              />
            ))}
          </div>
        )}
      </main>
      {selectedMovie && (
        <MoviePlayer movie={selectedMovie} onClose={handleClosePlayer} />
      )}
    </>
  );
};

export default Saved;
